export interface BattleStats {
  duration: number; // in seconds
  collisions: number;
  p1Healing: number;
  p2Healing: number;
  p1DamageDealt: number; // total damage
  p2DamageDealt: number; // total damage
  p1NormalDamageDealt: number; // basic physical attack damage
  p2NormalDamageDealt: number; // basic physical attack damage
  p1SkillDamageDealt: number;  // skill/magic attack damage
  p2SkillDamageDealt: number;  // skill/magic attack damage
  p1MaxSingleHit: number;       // highest damage dealt in a single blow
  p2MaxSingleHit: number;       // highest damage dealt in a single blow
  p1SkillCasts: number;         // number of skills executed
  p2SkillCasts: number;         // number of skills executed
  p1DodgeCount: number;         // Total dodges / escapes
  p2DodgeCount: number;         // Total dodges / escapes
  p1MaxSpeed: number;           // Maximum physical velocity reached
  p2MaxSpeed: number;           // Maximum physical velocity reached
  p1Bounces: number;            // Wall bounces count
  p2Bounces: number;            // Wall bounces count
  p1CritStrikes: number;        // Critical/Heavy impacts count
  p2CritStrikes: number;        // Critical/Heavy impacts count
  p1ShieldAbsorbed: number;     // Shield damage absorbed
  p2ShieldAbsorbed: number;     // Shield damage absorbed
}

const getSubSkillMaxCooldown = (charId: string) => {
  const cooldowns: Record<string, number> = {
    vampire: 18.0,
    mud: 15.0,
    blaze: 16.0,
    lightning: 15.0,
    dice: 14.0,
    gravity: 18.0,
    phantom: 12.0,
    cat: 10.0,
    snake: 9.0,
    grid9: 12.0,
    silent: 9.0,
    explorer: 10.0,
    conductor: 15.5,
    flash_bird: 7.0,
    gambler: 10.0,
    angel: 28.0
  };
  return cooldowns[charId] || 12;
};

export const createStatsTracker = (): BattleStats & { startTime: number; isPhysCollisionActive: boolean } => {
  let _p1DamageDealt = 0;
  let _p2DamageDealt = 0;
  let _p1NormalDamageDealt = 0;
  let _p2NormalDamageDealt = 0;
  let _p1SkillDamageDealt = 0;
  let _p2SkillDamageDealt = 0;
  let _p1MaxSingleHit = 0;
  let _p2MaxSingleHit = 0;
  let _p1SkillCasts = 0;
  let _p2SkillCasts = 0;
  
  return {
    startTime: Date.now(),
    duration: 0,
    collisions: 0,
    p1Healing: 0,
    p2Healing: 0,
    isPhysCollisionActive: false,
    p1DodgeCount: 0,
    p2DodgeCount: 0,
    p1MaxSpeed: 0,
    p2MaxSpeed: 0,
    p1Bounces: 0,
    p2Bounces: 0,
    p1CritStrikes: 0,
    p2CritStrikes: 0,
    p1ShieldAbsorbed: 0,
    p2ShieldAbsorbed: 0,
    
    get p1DamageDealt() { return _p1DamageDealt; },
    set p1DamageDealt(val) {
      const diff = val - _p1DamageDealt;
      if (diff > 0) {
        if (this.isPhysCollisionActive) {
          _p1NormalDamageDealt += diff;
        } else {
          _p1SkillDamageDealt += diff;
        }
        if (diff > _p1MaxSingleHit) {
          _p1MaxSingleHit = diff;
        }
        if (diff >= 5.0) {
          this.p1CritStrikes = (this.p1CritStrikes || 0) + 1;
        }
      }
      _p1DamageDealt = val;
    },
    
    get p2DamageDealt() { return _p2DamageDealt; },
    set p2DamageDealt(val) {
      const diff = val - _p2DamageDealt;
      if (diff > 0) {
        if (this.isPhysCollisionActive) {
          _p2NormalDamageDealt += diff;
        } else {
          _p2SkillDamageDealt += diff;
        }
        if (diff > _p2MaxSingleHit) {
          _p2MaxSingleHit = diff;
        }
        if (diff >= 5.0) {
          this.p2CritStrikes = (this.p2CritStrikes || 0) + 1;
        }
      }
      _p2DamageDealt = val;
    },
    
    get p1NormalDamageDealt() { return _p1NormalDamageDealt; },
    set p1NormalDamageDealt(v) { _p1NormalDamageDealt = v; },
    get p2NormalDamageDealt() { return _p2NormalDamageDealt; },
    set p2NormalDamageDealt(v) { _p2NormalDamageDealt = v; },
    
    get p1SkillDamageDealt() { return _p1SkillDamageDealt; },
    set p1SkillDamageDealt(v) { _p1SkillDamageDealt = v; },
    get p2SkillDamageDealt() { return _p2SkillDamageDealt; },
    set p2SkillDamageDealt(v) { _p2SkillDamageDealt = v; },
    
    get p1MaxSingleHit() { return _p1MaxSingleHit; },
    set p1MaxSingleHit(v) { _p1MaxSingleHit = v; },
    get p2MaxSingleHit() { return _p2MaxSingleHit; },
    set p2MaxSingleHit(v) { _p2MaxSingleHit = v; },
    
    get p1SkillCasts() { return _p1SkillCasts; },
    set p1SkillCasts(v) { _p1SkillCasts = v; },
    get p2SkillCasts() { return _p2SkillCasts; },
    set p2SkillCasts(v) { _p2SkillCasts = v; },
  };
};

