  // Real-time cumulative damage states with instant pop-up highlights
  const [p1Damage, setP1Damage] = useState<number>(0);
  const [p2Damage, setP2Damage] = useState<number>(0);
  const [p1LatestHit, setP1LatestHit] = useState<number>(0);
  const [p2LatestHit, setP2LatestHit] = useState<number>(0);
  const [p1HitActive, setP1HitActive] = useState<boolean>(false);
  const [p2HitActive, setP2HitActive] = useState<boolean>(false);
  const isConcludedRef = useRef<boolean>(false);

  const triggerGameOver = (winner: 'p1' | 'p2', stats: any) => {
    if (isConcludedRef.current) return;
    isConcludedRef.current = true;
    
    if (winner === 'p1') {
      const nextScore = p1Score + 1;
      setP1Score(nextScore);
      localStorage.setItem('sphere_battle_score_p1', String(nextScore));
    } else {
      const nextScore = p2Score + 1;
      setP2Score(nextScore);
      localStorage.setItem('sphere_battle_score_p2', String(nextScore));
    }
    const nextRound = matchRound + 1;
    setMatchRound(nextRound);
    localStorage.setItem('sphere_battle_round', String(nextRound));

    onGameOver(winner, stats);
  };

