              const boundedPercent = Math.min(avgPercent, currentHpPercent + 0.20);
              
              ball.hp = Math.round(boundedPercent * ball.maxHp);
              target.hp = Math.round((avgPercent - (boundedPercent - currentHpPercent)) * target.maxHp);
              
              addFloatingText('⚖️ 天平制衡 HP 等額平均!', ball.x, ball.y - 12, '#38bdf8');
